arguments.command:
perl -e '
use strict;
open(my $fh, "<", "/app/answers.json") or die "Cannot open: $!";
local $/;
my $content = <$fh>;
close($fh);
# Basic JSON structure check
if ($content =~ /^\s*\{/ && $content =~ /\}\s*$/ &&
    $content =~ /"recommendation"/ &&
    $content =~ /"classification"/ &&
    $content =~ /"implication"/) {
    print "File exists and contains required JSON keys: recommendation, classification, implication\n";
} else {
    print "JSON structure issue\n";
}
'

